 1→import { useEffect, useRef, useState } from 'react';
 2→import { isTauri } from '../platform';
 3→
 4→export function useDbSearch<TRow, TEntry>(
 5→  query: string,
 6→  dbSearch: (query: string) => Promise<TRow[]>,
 7→  rowToEntry: (row: TRow) => TEntry,
 8→): TEntry[] | null {
 9→  const [results, setResults] = useState<TEntry[] | null>(null);
10→  const requestIdRef = useRef(0);
11→
12→  useEffect(() => {
13→    if (!isTauri || !query.trim()) {
14→      setResults(null);
15→      return;
16→    }
17→
18→    const requestId = ++requestIdRef.current;
19→
20→    dbSearch(query)
21→      .then(rows => {
22→        if (requestId !== requestIdRef.current) return;
23→        setResults(rows.map(rowToEntry));
24→      })
25→      .catch(err => {
26→        console.error('FTS5 search failed:', err);
27→        if (requestId === requestIdRef.current) {
28→          setResults(null);
29→        }
30→      });
31→  }, [
32→    query,
33→    dbSearch,
34→    rowToEntry,
35→  ]);
36→
37→  return results;
38→}
