643→      ]);
644→      await db.execute('INSERT INTO recent_commands (command_id) VALUES ($1)', [
645→        commandId,
646→      ]);
647→      await db.execute(
648→        `DELETE FROM recent_commands WHERE id NOT IN (
649→          SELECT id FROM recent_commands ORDER BY used_at DESC LIMIT 10
650→        )`,
651→      );
652→      return;
653→    }
654→    const all = await this.getAll();
655→    const next = [
