684→  async set(key: string, value: string): Promise<void> {
685→    if (isTauri) {
686→      const db = await getDb();
687→      await db.execute(
688→        'INSERT INTO settings (key, value) VALUES ($1, $2) ON CONFLICT(key) DO UPDATE SET value = excluded.value',
689→        [
690→          key,
691→          value,
692→        ],
693→      );
694→      return;
695→    }
696→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
697→    const existing = all.findIndex(r => r.key === key);
698→    if (existing >= 0) {
699→      all[existing] = {
700→        key,
701→        value,
702→      };
703→    } else {
704→      all.push({
705→        key,
706→        value,
707→      });
708→    }
709→    storageSet('settings-all', all);
710→  },
711→  async delete(key: string): Promise<void> {
712→    if (isTauri) {
713→      const db = await getDb();
714→      await db.execute('DELETE FROM settings WHERE key = $1', [key]);
715→      return;
716→    }
717→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
718→    storageSet(
719→      'settings-all',
720→      all.filter(r => r.key !== key),
721→    );
722→  },
723→  async getAll(): Promise<SettingRow[]> {
724→    if (isTauri) {
725→      const db = await getDb();
726→      return db.select<SettingRow[]>('SELECT key, value FROM settings');
727→    }
728→    return storageGet('settings-all', isSettingRowArray) ?? [];
729→  },
730→};
