  1→import { useCallback, useEffect, useRef, useState } from 'react';
  2→import type { ClipboardEntry } from '../data/clipboard_data';
  3→import { MOCK_CLIPBOARD_ENTRIES } from '../data/clipboard_data';
  4→import type { ClipboardChangeEvent } from '../platform';
  5→import { getPlatform, isTauri } from '../platform';
  6→import type { ClipboardEntryRow } from '../utils/database';
  7→import { clipboardDb } from '../utils/database';
  8→
  9→const MAX_ENTRIES = 1000;
 10→
 11→const VALID_CONTENT_TYPES = new Set<ClipboardEntry['contentType']>([
 12→  'text',
 13→  'link',
 14→  'color',
 15→  'image',
 16→]);
 17→
 18→function validContentType(value: string): ClipboardEntry['contentType'] {
 19→  return VALID_CONTENT_TYPES.has(value as ClipboardEntry['contentType'])
 20→    ? (value as ClipboardEntry['contentType'])
 21→    : 'text';
 22→}
 23→
 24→export function rowToEntry(row: ClipboardEntryRow): ClipboardEntry {
 25→  const date = new Date(row.copied_at);
 26→  return {
 27→    id: row.id,
 28→    content: row.content,
 29→    contentType: validContentType(row.content_type),
 30→    sourceApp: row.source_app,
 31→    sourceIcon: null,
 32→    copiedAt: isNaN(date.getTime()) ? new Date() : date,
 33→    pinned: row.pinned === 1,
 34→  };
 35→}
 36→
 37→function entryToRow(entry: ClipboardEntry): ClipboardEntryRow {
 38→  return {
 39→    id: entry.id,
 40→    content: entry.content,
 41→    content_type: entry.contentType,
 42→    source_app: entry.sourceApp,
 43→    copied_at: entry.copiedAt.toISOString(),
 44→    pinned: entry.pinned ? 1 : 0,
 45→  };
 46→}
 47→
 48→function createEntryFromEvent(event: ClipboardChangeEvent): ClipboardEntry {
 49→  return {
 50→    id: `clip-${event.timestamp}-${Math.random().toString(36).slice(2, 8)}`,
 51→    content: event.content,
 52→    contentType: event.contentType,
 53→    sourceApp: 'System',
 54→    sourceIcon: null,
 55→    copiedAt: new Date(event.timestamp),
 56→    pinned: false,
 57→  };
 58→}
 59→
 60→function trimToMaxEntries(entries: ClipboardEntry[]): {
 61→  kept: ClipboardEntry[];
 62→  removed: string[];
 63→} {
 64→  if (entries.length <= MAX_ENTRIES)
 65→    return {
 66→      kept: entries,
 67→      removed: [],
 68→    };
 69→  const pinned = entries.filter(e => e.pinned);
 70→  const unpinned = entries.filter(e => !e.pinned);
 71→  const unpinnedLimit = Math.max(0, MAX_ENTRIES - pinned.length);
 72→  const kept = [
 73→    ...pinned,
 74→    ...unpinned.slice(0, unpinnedLimit),
 75→  ];
 76→  const removedIds = unpinned.slice(unpinnedLimit).map(e => e.id);
 77→  return {
 78→    kept,
 79→    removed: removedIds,
 80→  };
 81→}
 82→
 83→export function useClipboardHistory() {
 84→  const [entries, setEntries] = useState<ClipboardEntry[]>([]);
 85→  const entriesRef = useRef<ClipboardEntry[]>([]);
 86→
 87→  useEffect(() => {
 88→    entriesRef.current = entries;
 89→  }, [entries]);
 90→
 91→  useEffect(() => {
 92→    let aborted = false;
 93→
 94→    clipboardDb
 95→      .getAll(MAX_ENTRIES)
 96→      .then(rows => {
 97→        if (aborted) return;
 98→        if (rows.length > 0) {
 99→          setEntries(rows.map(rowToEntry));
100→        } else if (!isTauri) {
101→          const mock = MOCK_CLIPBOARD_ENTRIES.map(e => ({ ...e }));
102→          setEntries(mock);
103→          Promise.all(mock.map(e => clipboardDb.insert(entryToRow(e)))).catch(
104→            console.error,
105→          );
106→        }
107→      })
108→      .catch(err => {
109→        console.error('Failed to load clipboard history:', err);
110→        if (!isTauri && !aborted) {
111→          setEntries(MOCK_CLIPBOARD_ENTRIES.map(e => ({ ...e })));
112→        }
113→      });
114→
115→    return () => {
116→      aborted = true;
117→    };
118→  }, []);
119→
120→  useEffect(() => {
121→    if (!isTauri) return;
122→
123→    let unsubscribe: (() => void) | undefined;
124→    let cancelled = false;
125→
126→    getPlatform()
127→      .clipboard.onClipboardChange((event: ClipboardChangeEvent) => {
128→        if (cancelled) return;
129→
130→        const prev = entriesRef.current;
131→        const existing = prev.find(
132→          e => e.content === event.content && !e.pinned,
133→        );
134→
135→        let next: ClipboardEntry[];
136→        if (existing) {
137→          const updated = {
138→            ...existing,
139→            copiedAt: new Date(event.timestamp),
140→          };
141→          next = [
142→            updated,
143→            ...prev.filter(e => e.id !== existing.id),
144→          ];
145→          clipboardDb
146→            .update(existing.id, {
147→              copied_at: updated.copiedAt.toISOString(),
148→            })
149→            .catch(console.error);
150→        } else {
151→          const newEntry = createEntryFromEvent(event);
152→          next = [
153→            newEntry,
154→            ...prev,
155→          ];
156→          clipboardDb.insert(entryToRow(newEntry)).catch(console.error);
157→        }
158→
159→        const { kept, removed } = trimToMaxEntries(next);
160→        if (removed.length > 0) {
161→          Promise.all(removed.map(id => clipboardDb.delete(id))).catch(
162→            console.error,
163→          );
164→        }
165→
166→        setEntries(kept);
167→      })
168→      .then(unsub => {
169→        if (cancelled) {
170→          unsub();
171→        } else {
172→          unsubscribe = unsub;
173→        }
174→      });
175→
176→    return () => {
177→      cancelled = true;
178→      unsubscribe?.();
179→    };
180→  }, []);
181→
182→  const togglePin = useCallback((entryId: string) => {
183→    setEntries(prev => {
184→      const entry = prev.find(e => e.id === entryId);
185→      if (!entry) return prev;
186→      const newPinned = !entry.pinned;
187→      clipboardDb
188→        .update(entryId, { pinned: newPinned ? 1 : 0 })
189→        .catch(console.error);
190→      return prev.map(e =>
191→        e.id === entryId
192→          ? {
193→              ...e,
194→              pinned: newPinned,
195→            }
196→          : e);
197→    });
198→  }, []);
199→
200→  const deleteEntry = useCallback((entryId: string) => {
201→    setEntries(prev => prev.filter(e => e.id !== entryId));
202→    clipboardDb.delete(entryId).catch(console.error);
203→  }, []);
204→
205→  const clearAll = useCallback(() => {
206→    setEntries([]);
207→    clipboardDb.clear().catch(console.error);
208→  }, []);
209→
210→  return {
211→    entries,
212→    togglePin,
213→    deleteEntry,
214→    clearAll,
215→  };
216→}
