535→                if (recentItems.length > 0) {
536→                  sections.push(
537→                    <ListSection key="recent" title="Recent">
538→                      {recentItems.map(entry => {
539→                        const idx = globalIndex++;
540→                        return (
541→                          <ListItem
542→                            key={entry.id}
543→                            index={idx}
544→                            icon={renderClipboardIcon(entry)}
545→                            title={truncateContent(entry.content, 60)}
546→                            subtitle={entry.sourceApp}
547→                            accessories={[
548→                              {
549→                                text: formatRelativeDate(entry.copiedAt, now),
550→                                tooltip: entry.copiedAt.toLocaleString(),
551→                              },
552→                            ]}
553→                            query={query || undefined}
554→                          />
555→                        );
556→                      })}
557→                    </ListSection>,
558→                  );
559→                }
