561→                return sections;
562→              })()}
563→            </List>
564→          )}
565→        </div>
566→      </div>
567→      <ActionPanel
568→        contextLabel="Clipboard History"
569→        actions={[
570→          {
571→            label: 'Paste',
572→            shortcut: <Kbd keys={['↵']} />,
573→          },
574→          {
575→            label: 'Actions',
576→            shortcut: (
577→              <Kbd
578→                keys={[
579→                  '⌘',
580→                  'K',
581→                ]}
582→              />
583→            ),
584→            onClick: toggleActions,
