 100→function rowToEntry(row: QuicklinkRow): QuicklinkEntry {
 101→  const parsed = new Date(row.created_at);
 102→  const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
 103→  const type = isQuicklinkType(row.type) ? row.type : 'url';
 104→
 105→  let tags:
 106→    | {
 107→        text: string;
 108→        color?: TagColor;
 109→      }[]
 110→    | undefined;
 111→  if (row.tags) {
 112→    try {
 113→      const rawTags = JSON.parse(row.tags);
 114→      if (Array.isArray(rawTags)) {
 115→        const validated = rawTags
 116→          .filter(
 117→            (
 118→              t,
 119→            ): t is {
 120→              text: string;
 121→              color?: string;
 122→            } =>
 123→              typeof t === 'object' && t !== null && typeof t.text === 'string',
 124→          )
 125→          .map(t => ({
 126→            text: t.text,
 127→            color:
 128→              typeof t.color === 'string' && isTagColor(t.color)
 129→                ? t.color
 130→                : undefined,
 131→          }));
 132→        if (validated.length > 0) {
 133→          tags = validated;
 134→        }
 135→      }
 136→    } catch {
 137→      /* empty */
 138→    }
 139→  }
 140→
 141→  return {
 142→    id: row.id,
 143→    name: row.name,
 144→    link: row.link,
 145→    type,
 146→    application: row.application ?? undefined,
 147→    icon: getQuicklinkIcon(type),
 148→    tags,
 149→    createdAt,
 150→  };
 151→}
